content_object.local_agent_node_spawn:
import { spawn } from "node:child_process";

export async function runCliProvider(input: {
  command: string;
  args: string[];
  stdin?: string;
  cwd: string;
  timeoutMs: number;
  envAllowList?: Record<string, string>;
}): Promise<{ stdout: string; stderr: string; exitCode: number | null }> {
  return await new Promise((resolve, reject) => {
    const child = spawn(input.command, input.args, {
      cwd: input.cwd,
      shell: false,
      env: {
        PATH: process.env.PATH ?? "",
        HOME: process.env.HOME ?? "",
        USERPROFILE: process.env.USERPROFILE ?? "",
        ...input.envAllowList,
      },
    });

    let stdout = "";
    let stderr = "";

    const timer = setTimeout(() => {
      child.kill("SIGTERM");
      reject(new Error("CLI provider timed out"));
    }, input.timeoutMs);

    child.stdout.on("data", chunk => {
      stdout += chunk.toString();
      // emit NormalizedEvent: source=stdout
    });

    child.stderr.on("data", chunk => {
      stderr += chunk.toString();
      // emit NormalizedEvent: source=stderr
    });

    child.on("error", err => {
      clearTimeout(timer);
      reject(err);
    });

    child.on("close", exitCode => {
      clearTimeout(timer);
      resolve({ stdout, stderr, exitCode });
    });

    if (input.stdin) child.stdin.write(input.stdin);
    child.stdin.end();
  });
}

